from functools import total_ordering

@total_ordering
class Money:
    __slots__ = ('cents',)            # no __dict__: smaller, faster attribute access

    def __init__(self, cents: int):
        self.cents = cents

    def __repr__(self) -> str:        # unambiguous, for developers/logs
        return f'Money(cents={self.cents})'

    def __eq__(self, other) -> bool:
        if not isinstance(other, Money):
            return NotImplemented     # let Python try the reflected op
        return self.cents == other.cents

    def __lt__(self, other) -> bool:
        if not isinstance(other, Money):
            return NotImplemented
        return self.cents < other.cents

    def __hash__(self) -> int:        # must be defined if __eq__ is, to stay hashable
        return hash(self.cents)

    def __add__(self, other: 'Money') -> 'Money':
        return Money(self.cents + other.cents)

# @total_ordering fills in <=, >, >= from __eq__ and __lt__.
assert Money(150) < Money(200)
assert sorted([Money(200), Money(150)])[0] == Money(150)

def read_large_file(path):
    # Streams one line at a time; never loads the whole file into RAM.
    with open(path, 'r') as f:
        for line in f:
            yield line.rstrip('\n')

def parse(lines):
    for line in lines:
        if line and not line.startswith('#'):
            yield line.split(',')

# Lazy pipeline: each stage pulls from the previous, one record at a time.
rows = parse(read_large_file('huge.csv'))
first_ten = [next(rows) for _ in range(10)]   # processes only 10 lines of a 10GB file

# yield from delegates to a sub-iterator (and forwards send/throw):
def flatten(nested):
    for item in nested:
        if isinstance(item, list):
            yield from flatten(item)
        else:
            yield item

import functools, time

def retry(times=3, delay=0.1):
    def decorator(fn):
        @functools.wraps(fn)                 # preserve metadata of fn
        def wrapper(*args, **kwargs):
            last = None
            for attempt in range(times):
                try:
                    return fn(*args, **kwargs)
                except Exception as e:
                    last = e
                    time.sleep(delay * (2 ** attempt))   # exponential backoff
            raise last
        return wrapper
    return decorator

@retry(times=5)
def call_flaky_api():
    ...

# Context managers handle deterministic setup/teardown via __enter__/__exit__.
from contextlib import contextmanager

@contextmanager
def timed(label):
    start = time.perf_counter()
    try:
        yield                                # body of the 'with' runs here
    finally:
        print(f'{label}: {time.perf_counter() - start:.3f}s')   # runs even on exception

with timed('query'):
    result = run_query()

